import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                pkgs[pkg['id']] = pkg.get('resolvedVersion', pkg.get('requestedVersion',''))
        result[name] = pkgs
    return result

b = get_pkgs(baseline)
a = get_pkgs(after)
print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg, 'N/A')
        av = ap.get(pkg, 'N/A')
        if bv != av:
            print(f'  {proj}: {pkg} {bv} -> {av}')
            changes = True
if not changes:
    print('  None')
print('=== UNCHANGED (sample) ===')
count = 0
for proj in sorted(b.keys()):
    for pkg in sorted(b.get(proj, {}).keys()):
        bv = b[proj].get(pkg,'')
        av = a.get(proj, {}).get(pkg,'')
        if bv == av:
            print(f'  {proj}: {pkg} {bv}')
            count += 1
print(f'Total unchanged: {count}')
"

